import type { Client } from "@libsql/client";
import { getRun } from "workflow/api";
import { loadRhapsodyConfig } from "@/lib/config";
import {
	createStateStoreClient,
	listStaleRunningAttempts,
	type ReconcileStaleRunningAttemptResult,
	reconcileStaleRunningAttempt,
	type StaleRunningAttempt,
} from "@/lib/state";

const DEFAULT_RECONCILER_LIMIT = 20;

export type ReconcilerTickInput = {
	now?: number;
	maxRunningAttemptAgeMs?: number;
	limit?: number;
	client?: Client;
};

export type ReconcilerTickResponse = {
	scanned: number;
	reconciled: number;
	skipped: number;
	limits: {
		maxRunningAttemptAgeMs: number;
		limit: number;
		cutoff: number;
	};
	staleAttempts: StaleRunningAttempt[];
	results: ReconcileStaleRunningAttemptResult[];
	workflowCancellations: ReconcilerWorkflowCancellationResult[];
};

export type ReconcilerWorkflowCancellationResult =
	| {
			attempted: false;
			runId: string;
			attemptId: string;
			reason: "not_reconciled" | "missing_workflow_run_id";
	  }
	| {
			attempted: true;
			runId: string;
			attemptId: string;
			runnerWorkflowRunId: string;
			cancelled: true;
	  }
	| {
			attempted: true;
			runId: string;
			attemptId: string;
			runnerWorkflowRunId: string;
			cancelled: false;
			error: { name: string; message: string };
	  };

export async function runReconcilerTick(
	input: ReconcilerTickInput = {},
): Promise<ReconcilerTickResponse> {
	const client = input.client ?? createStateStoreClient();

	try {
		return await runReconcilerTickWithClient(client, input);
	} finally {
		if (!input.client) {
			client.close();
		}
	}
}

async function runReconcilerTickWithClient(
	client: Client,
	input: Omit<ReconcilerTickInput, "client">,
): Promise<ReconcilerTickResponse> {
	const config = loadRhapsodyConfig();
	const now = input.now ?? Date.now();
	const maxRunningAttemptAgeMs =
		input.maxRunningAttemptAgeMs ?? config.runner.runningAttemptTimeoutMs;
	const limit = input.limit ?? DEFAULT_RECONCILER_LIMIT;
	const cutoff = now - maxRunningAttemptAgeMs;
	const staleAttempts = await listStaleRunningAttempts(client, {
		cutoff,
		limit,
	});
	const results: ReconcileStaleRunningAttemptResult[] = [];
	const workflowCancellations: ReconcilerWorkflowCancellationResult[] = [];

	for (const attempt of staleAttempts) {
		const result = await reconcileStaleRunningAttempt(client, {
			runId: attempt.runId,
			attemptId: attempt.attemptId,
			now,
			reason: "running_attempt_age_exceeded",
			maxRunningAttemptAgeMs,
		});
		results.push(result);
		workflowCancellations.push(
			await cancelRunnerWorkflowForReconciledAttempt(result),
		);
	}

	const reconciled = results.filter((result) => result.applied).length;

	return {
		scanned: staleAttempts.length,
		reconciled,
		skipped: results.length - reconciled,
		limits: {
			maxRunningAttemptAgeMs,
			limit,
			cutoff,
		},
		staleAttempts,
		results,
		workflowCancellations,
	};
}

async function cancelRunnerWorkflowForReconciledAttempt(
	result: ReconcileStaleRunningAttemptResult,
): Promise<ReconcilerWorkflowCancellationResult> {
	if (!result.applied) {
		return {
			attempted: false,
			runId: result.runId,
			attemptId: result.attemptId,
			reason: "not_reconciled",
		};
	}

	if (!result.runnerWorkflowRunId) {
		return {
			attempted: false,
			runId: result.runId,
			attemptId: result.attemptId,
			reason: "missing_workflow_run_id",
		};
	}

	try {
		const run = getRun(result.runnerWorkflowRunId);
		await run.cancel();
		return {
			attempted: true,
			runId: result.runId,
			attemptId: result.attemptId,
			runnerWorkflowRunId: result.runnerWorkflowRunId,
			cancelled: true,
		};
	} catch (error) {
		return {
			attempted: true,
			runId: result.runId,
			attemptId: result.attemptId,
			runnerWorkflowRunId: result.runnerWorkflowRunId,
			cancelled: false,
			error: serializeError(error),
		};
	}
}

function serializeError(error: unknown) {
	if (error instanceof Error) {
		return { name: error.name, message: error.message };
	}

	return { name: "UnknownError", message: String(error) };
}

agent_type.description:
Optional type name for the new agent. If omitted, `default` is used.
Available roles:
builder: {
Implementation-focused Sandkit worker for concrete, scoped code changes once the relevant code path is known.
- This role's model is set to `gpt-5.3-codex-spark` and its reasoning effort is set to `low`. These settings cannot be changed.
}
entire-search: {
Search Entire checkpoint history and transcripts with `entire search --json`. Use when the user asks about previous work, commits, sessions, prompts, or historical context in this repository.
- This role's reasoning effort is set to `medium` and cannot be changed.
}
default: {
Default agent.
}
explorer: {
Use `explorer` for specific codebase questions.
Explorers are fast and authoritative.
They must be used to ask specific, well-scoped questions on the codebase.
Rules:
- In order to avoid redundant work, you should avoid exploring the same problem that explorers have already covered. Typically, you should trust the explorer results without additional verification. You are still allowed to inspect the code yourself to gain the needed context!
- You are encouraged to spawn up multiple explorers in parallel when you have multiple distinct questions to ask about the codebase that can be answered independently. This allows you to get more information faster without waiting for one question to finish before asking the next. While waiting for the explorer results, you can continue working on other local tasks that do not depend on those results. This parallelism is a key advantage of delegation, so use it whenever you have multiple questions to ask.
- Reuse existing explorers for related questions.
}
worker: {
Use for execution and production work.
Typical tasks:
- Implement part of a feature
- Fix tests or bugs
- Split large refactors into independent chunks
